UPDATE email_templates SET
  body_html = '<table width="100%" cellpadding="0" cellspacing="0" bgcolor="#09090b" style="background-color:#09090b !important;"><tr><td align="center" bgcolor="#09090b" style="background-color:#09090b !important;padding:40px 20px;font-family:''Red Hat Display'',Arial,sans-serif;"><table cellpadding="0" cellspacing="0" bgcolor="#09090b" style="width:100%;max-width:480px;background-color:#09090b !important;border-radius:16px;"><tr><td align="center" bgcolor="#09090b" style="background-color:#09090b !important;padding:40px 32px 24px;"><img src="https://dash.complerer.com/logo-white.png" alt="Complerer" height="28" /></td></tr><tr><td bgcolor="#09090b" style="background-color:#09090b !important;padding:0 32px;"><h2 style="color:#fafafa !important;font-size:20px;font-weight:700;margin:0 0 8px;">{{alertTitle}}</h2><p style="color:#a1a1aa !important;font-size:14px;line-height:1.6;margin:0 0 20px;">{{alertMessage}}</p><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="padding-bottom:28px;"><table width="100%" cellpadding="0" cellspacing="0" bgcolor="#18181b" style="background-color:#18181b !important;border:1px solid #27272a;border-radius:10px;"><tr><td bgcolor="#18181b" style="background-color:#18181b !important;padding:14px 16px;"><p style="color:#71717a !important;font-size:11px;margin:0 0 6px;">Severity</p><p style="font-size:14px;font-weight:700;color:{{severityColor}};margin:0 0 12px;">{{severity}}</p><p style="color:#71717a !important;font-size:11px;margin:0 0 4px;">Framework</p><p style="color:#fafafa !important;font-size:14px;margin:0;">{{framework}}</p></td></tr></table></td></tr><tr><td align="center" style="padding-bottom:32px;"><a href="{{dashboardUrl}}" style="display:inline-block;background-color:#34d399 !important;color:#09090b !important;font-weight:700;padding:14px 36px;border-radius:12px;text-decoration:none;font-size:14px;">View Dashboard</a></td></tr></table></td></tr><tr><td align="center" bgcolor="#09090b" style="background-color:#09090b !important;padding:16px 32px 40px;border-top:1px solid #1c1c1f;"><p style="color:#3f3f46 !important;font-size:11px;margin:0;">Complerer · Compliance Platform</p></td></tr></table></td></tr></table>',
